const amqplib = require('amqplib');
const crypto = require('crypto');

// In production, use a secrets manager (AWS Secrets Manager, HashiCorp Vault, etc.)
const HMAC_SECRET = process.env.PAYMENT_HMAC_SECRET;
if (!HMAC_SECRET) {
  console.error('FATAL: PAYMENT_HMAC_SECRET environment variable is required');
  process.exit(1);
}

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.PAYMENT_QUEUE || 'payment_events';

// Track processed message IDs to prevent replay attacks
const processedMessageIds = new Set();
const MESSAGE_ID_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

function verifyMessageSignature(messageBody, signature) {
  if (!signature) {
    return false;
  }
  const expectedSignature = crypto
    .createHmac('sha256', HMAC_SECRET)
    .update(messageBody)
    .digest('hex');

  // Use timingSafeEqual to prevent timing attacks
  try {
    return crypto.timingSafeEqual(
      Buffer.from(signature, 'hex'),
      Buffer.from(expectedSignature, 'hex')
    );
  } catch {
    return false;
  }
}

function validatePaymentPayload(payment) {
  const errors = [];

  if (!payment.messageId || typeof payment.messageId !== 'string') {
    errors.push('Missing or invalid messageId');
  }
  if (!payment.paymentId || typeof payment.paymentId !== 'string') {
    errors.push('Missing or invalid paymentId');
  }
  if (!payment.amount || typeof payment.amount !== 'number' || payment.amount <= 0) {
    errors.push('Invalid amount: must be a positive number');
  }
  if (payment.amount > 100000) {
    errors.push('Amount exceeds maximum allowed threshold');
  }
  if (!payment.currency || typeof payment.currency !== 'string' || payment.currency.length !== 3) {
    errors.push('Invalid currency code');
  }
  if (!payment.timestamp || typeof payment.timestamp !== 'number') {
    errors.push('Missing or invalid timestamp');
  }
  if (!['charge', 'refund', 'authorize', 'capture'].includes(payment.action)) {
    errors.push('Invalid payment action');
  }

  // Reject messages older than 5 minutes (prevent replay of old messages)
  const messageAge = Date.now() - payment.timestamp;
  if (messageAge > 5 * 60 * 1000) {
    errors.push('Message timestamp is too old (possible replay attack)');
  }
  if (messageAge < -60 * 1000) {
    errors.push('Message timestamp is in the future');
  }

  return errors;
}

function isDuplicate(messageId) {
  if (processedMessageIds.has(messageId)) {
    return true;
  }
  processedMessageIds.add(messageId);

  // Clean up old message IDs periodically
  setTimeout(() => {
    processedMessageIds.delete(messageId);
  }, MESSAGE_ID_TTL_MS);

  return false;
}

